parameters.functionCode:
const vehicles = $input.first().json;

const needsService = vehicles.filter(v => {
  const issues = [];

  if (v.oilLife < 15) issues.push({ type: 'Oil Change', urgency: v.oilLife < 5 ? 'URGENT' : 'SOON' });
  if (v.tirePressure < 30) issues.push({ type: 'Tire Service', urgency: 'SOON' });
  if (v.brakePadLife < 20) issues.push({ type: 'Brake Inspection', urgency: v.brakePadLife < 10 ? 'URGENT' : 'SOON' });
  if (v.batteryHealth < 50) issues.push({ type: 'Battery Check', urgency: v.batteryHealth < 30 ? 'URGENT' : 'SOON' });
  if (v.mileage - v.lastServiceMiles > 5000) issues.push({ type: 'Scheduled Maintenance', urgency: v.mileage - v.lastServiceMiles > 7500 ? 'URGENT' : 'SOON' });

  v.predictedIssues = issues;
  return issues.length > 0;
});

return { needsService, count: needsService.length };

parameters.prompt:
