Owner: {{ $json.ownerName }}
Car: {{ $json.year }} {{ $json.make }} {{ $json.model }}
Issues: {{ $json.predictedIssues.map(i => i.type).join(', ') }}
Urgency: {{ $json.predictedIssues[0].urgency }}

Keep under 160 characters, friendly but professional.

parameters.functionCode:
const availability = $input.first().json.slots;
const preferredTime = availability.find(s => s.time.includes('09:00') || s.time.includes('10:00')) || availability[0];

return { proposedSlot: preferredTime, alternativeSlots: availability.slice(1, 3) };

